1 = 1

	AND A.ZIPCODE = #{zipcode, jdbcType=VARCHAR}


	AND A.SIDO = #{sido, jdbcType=VARCHAR}


	AND A.SIGUNGU like '%' || #{sigungu, jdbcType=VARCHAR} || '%'


	AND A.TOWN like '%' || #{town, jdbcType=VARCHAR} || '%'


	AND A.ROADNAME like '%' || #{roadname, jdbcType=VARCHAR} || '%'


	AND (A.BLDG_MAINNO = #{bldg_mainno, jdbcType=VARCHAR} OR A.JIBUN_BONBUN = #{bldg_mainno, jdbcType=VARCHAR})


	AND (A.BLDG_SUBNO = #{bldg_subno, jdbcType=VARCHAR} OR A.JIBUN_BUBUN = #{bldg_subno, jdbcType=VARCHAR})


	AND A.RI = #{ri, jdbcType=VARCHAR}


	AND A.LEGAL_DONG = #{legal_dong, jdbcType=VARCHAR}


	AND (A.DONG like '%' ||  #{dong, jdbcType=VARCHAR} || '%' OR A.ROADNAME like '%' ||  #{dong, jdbcType=VARCHAR} || '%')



	AND A.JIBUN_BONBUN = #{jibun_bonbun, jdbcType=VARCHAR}


	AND A.JIBUN_BUBUN = #{jibun_bubun, jdbcType=VARCHAR}

mapper.select:
SELECT A.ZIPCODE, A.NEWKADDR, PASTKADDR, A.EADDR, A.RNUM FROM ( SELECT A.ZIPCODE, A.NEWKADDR, PASTKADDR, A.EADDR, ROWNUM AS RNUM FROM ( SELECT A.zipcode, A.SIDO || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE ' ' || A.SIGUNGU END) || (CASE WHEN A.TOWN IS NULL THEN '' WHEN A.TOWN = 'NULL' THEN '' WHEN A.TOWN = '' THEN '' ELSE ' ' || A.TOWN END) || (CASE WHEN A.ROADNAME IS NULL THEN '' ELSE ' ' || A.ROADNAME END) || (CASE WHEN A.BLDG_MAINNO IS NULL THEN '' ELSE ' ' || A.BLDG_MAINNO END) || (CASE WHEN A.BLDG_SUBNO IS NULL THEN '' WHEN A.BLDG_SUBNO = '0' THEN '' ELSE '-'|| A.BLDG_SUBNO END) --|| (CASE WHEN A.BLDGNAME IS NULL THEN '' WHEN A.BLDGNAME = 'NULL' THEN '' WHEN A.BLDGNAME = '' THEN '' ELSE '(' || A.BLDGNAME || ')' END) AS NEWKADDR, A.SIDO || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE ' ' || A.SIGUNGU END) || (CASE WHEN NVL(A.DONG, 'NULL') = 'NULL' AND NVL(A.LEGAL_DONG, 'NULL') != 'NULL' THEN ' ' || A.LEGAL_DONG WHEN NVL(A.LEGAL_DONG, 'NULL') = 'NULL' AND NVL(A.DONG, 'NULL') != 'NULL' THEN ' ' || A.DONG WHEN NVL(A.DONG, 'NULL') = 'NULL' AND NVL(A.LEGAL_DONG, 'NULL') = 'NULL' THEN '' ELSE ' ' || A.LEGAL_DONG END) || (CASE WHEN A.RI IS NULL THEN '' WHEN A.RI = 'NULL' THEN '' WHEN A.RI = '' THEN '' ELSE ' ' || A.RI END) || (CASE WHEN A.JIBUN_BONBUN IS NOT NULL THEN ' ' || A.JIBUN_BONBUN END) || (CASE WHEN A.JIBUN_BUBUN IS NULL THEN '' WHEN A.JIBUN_BUBUN = '0' THEN '' ELSE '-'|| A.JIBUN_BUBUN END) --|| (CASE WHEN A.BLDGNAME IS NULL THEN '' WHEN A.BLDGNAME = 'NULL' THEN '' WHEN A.BLDGNAME = '' THEN '' ELSE '(' || A.BLDGNAME || ')' END) AS PASTKADDR,
BIF.UF_CONVERT_HAN_TO_ENG(A.SIDO || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE ' ' || A.SIGUNGU END) || (CASE WHEN A.TOWN IS NULL THEN '' WHEN A.TOWN = 'NULL' THEN '' WHEN A.TOWN = '' THEN '' ELSE ' ' || A.TOWN END) || (CASE WHEN A.ROADNAME IS NULL THEN '' ELSE ' ' || A.ROADNAME END) --|| (CASE WHEN A.BLDGNAME IS NULL THEN '' WHEN A.BLDGNAME = 'NULL' THEN '' WHEN A.BLDGNAME = '' THEN '' ELSE '(' || A.BLDGNAME || ')' END) || (CASE WHEN A.BLDG_MAINNO IS NULL THEN '' ELSE ' ' || A.BLDG_MAINNO END) || (CASE WHEN A.BLDG_SUBNO IS NULL THEN '' WHEN A.BLDG_SUBNO = '0' THEN '' ELSE '-'|| A.BLDG_SUBNO END),'Y') AS EADDR FROM BIF.TB_NEWZIPCODE A WHERE (UPPER( A.SIDO || ' ' || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE A.SIGUNGU END) || ' ' || (CASE WHEN A.TOWN IS NULL THEN '' WHEN A.TOWN = 'NULL' THEN '' WHEN A.TOWN = '' THEN '' ELSE A.TOWN END) || ' ' || (CASE WHEN A.ROADNAME IS NULL THEN '' ELSE A.ROADNAME END) || ' ' || (CASE WHEN A.BLDG_MAINNO IS NULL THEN '' ELSE A.BLDG_MAINNO END) || (CASE WHEN A.BLDG_SUBNO IS NULL THEN '' WHEN A.BLDG_SUBNO = '0' THEN '' ELSE '-'|| A.BLDG_SUBNO END) || (CASE WHEN A.BLDGNAME IS NULL THEN '' WHEN A.BLDGNAME = 'NULL' THEN '' WHEN A.BLDGNAME = '' THEN '' ELSE '(' || A.BLDGNAME || ')' END) ) LIKE '%' || UPPER(#{dong, jdbcType=VARCHAR}) || '%' OR UPPER (A.SIDO || ' ' || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE A.SIGUNGU END) || ' ' || (CASE WHEN NVL(A.DONG, 'NULL') = 'NULL' AND NVL(A.LEGAL_DONG, 'NULL') != 'NULL' THEN ' ' || A.LEGAL_DONG WHEN NVL(A.LEGAL_DONG, 'NULL') = 'NULL' AND NVL(A.DONG, 'NULL') != 'NULL' THEN ' ' || A.DONG WHEN NVL(A.DONG, 'NULL') = 'NULL' AND NVL(A.LEGAL_DONG, 'NULL') = 'NULL' THEN '' ELSE ' ' || A.LEGAL_DONG END) || (CASE WHEN A.RI IS NULL THEN '' WHEN A.RI = 'NULL' THEN '' WHEN A.RI = '' THEN '' ELSE A.RI END) || ' ' || (CASE WHEN A.JIBUN_BONBUN IS NOT NULL THEN '' || A.JIBUN_BONBUN END) || (CASE WHEN A.JIBUN_BUBUN IS NULL THEN '' WHEN A.JIBUN_BUBUN = '0' THEN '' ELSE '-'|| A.JIBUN_BUBUN END) || (CASE WHEN A.BLDGNAME IS NULL THEN '' WHEN A.BLDGNAME = 'NULL' THEN '' WHEN A.BLDGNAME = '' THEN '' ELSE '(' || A.BLDGNAME || ')' END)) LIKE '%' || UPPER(#{dong, jdbcType=VARCHAR}) || '%' )
ORDER BY A.SIDO || ' ' || (CASE WHEN A.SIGUNGU IS NULL THEN '' ELSE A.SIGUNGU END) || ' ' || (CASE WHEN A.TOWN IS NULL THEN '' WHEN A.TOWN = 'NULL' THEN '' WHEN A.TOWN = '' THEN '' ELSE A.TOWN END) || ' ' || (CASE WHEN A.ROADNAME IS NULL THEN '' ELSE A.ROADNAME END) || ' ' || (CASE WHEN A.BLDG_MAINNO IS NULL THEN '' ELSE A.BLDG_MAINNO END) || (CASE WHEN A.BLDG_SUBNO IS NULL THEN '' WHEN A.BLDG_SUBNO = '0' THEN '' ELSE '-'|| A.BLDG_SUBNO END), NVL(A.BLDG_MAINNO, '999999'), NVL(A.BLDG_SUBNO, '999999') ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE A.RNUM >= #{firstIndex}
